/**
 * Constrói o item_id da API para busca de preço.
 * Ex: tier=6, base="SWORD", enc=0 → "T6_SWORD"
 *     tier=6, base="SWORD", enc=2 → "T6_SWORD_LEVEL2@2"
 */
function buildItemId(tier, base, enc) {
  if (!base) return null;
  enc = enc || 0;
  if (enc === 0) return `T${tier}_${base}`;
  return `T${tier}_${base}_LEVEL${enc}@${enc}`;
}

function buildArtifactId(tier, artKey) {
  if (!artKey) return null;
  return `T${tier}_${artKey}`;
}

function buildEncId(tier, encKey) {
  // Runa/Alma/Relíquia não têm tier no ID — sempre T4-T8
  return `T${tier}_${encKey}`;
}
